1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	type QuoteResult = { premium: number };
11	type ClaimResult = { payout: number; remainingCap: number };
12	type StepResult = QuoteResult | ClaimResult;
13	
14	const PROCESSING_FEE = 5;
15	const FIRST_INSURANCE_SURCHARGE = 0.1;
16	const LOYALTY_DISCOUNT = 0.2;
17	const LOYALTY_YEARS_THRESHOLD = 2;
18	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
19	const CURSE_SURCHARGE = 0.5;
20	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
21	const HIGH_ENCHANTMENT_THRESHOLD = 5;
22	const COMPONENT_BLOCK_SIZE = 3;
23	const COMPONENT_BLOCK_PRICE = 60;
24	
25	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
35	  sword: 1000,
36	  amulet: 600,
37	  staff: 800,
38	  potion: 400,
39	  rune: 250,
40	  moonstone: 250,
41	};
42	
43	const DEDUCTIBLE_PER_DAMAGE = 100;
44	const CAP_MULTIPLIER = 2;
45	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
46	const HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT = 0.5;
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	
50	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
51	
52	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
53	
54	const priceForComponentGroup = (type: string, count: number): number =>
55	  count === COMPONENT_BLOCK_SIZE
56	    ? COMPONENT_BLOCK_PRICE
57	    : count * BASE_PREMIUM_BY_TYPE[type];
58	
59	const countByType = (items: Item[]): Map<string, number> => {
60	  const counts = new Map<string, number>();
61	  for (const item of items) {
62	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
63	  }
64	  return counts;
65	};
66	
67	const sumBasePremiumsFor = (items: Item[]): number => {
68	  const mainItemsTotal = items
69	    .filter((item) => !isComponent(item))
70	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
71	
72	  const componentsTotal = Array.from(countByType(items.filter(isComponent)))
73	    .reduce((sum, [type, count]) => sum + priceForComponentGroup(type, count), 0);
74	
75	  return mainItemsTotal + componentsTotal;
76	};
77	
78	// Item surcharges: each rule adds a percentage of the item's base premium when it applies.
79	const ITEM_SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
80	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
81	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE },
82	];
83	
84	const surchargeRateFor = (item: Item): number =>
85	  ITEM_SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
86	
87	const itemSurchargesFor = (items: Item[]): number =>
88	  items.reduce((sum, item) => sum + basePremiumOf(item) * surchargeRateFor(item), 0);
89	
90	type PolicyContext = { customer: Customer; quoteIndex: number };
91	
92	// Policy modifiers: each rule applies a +/- percentage of the policy base when its predicate holds.
93	const POLICY_MODIFIER_RULES: { applies: (ctx: PolicyContext) => boolean; rate: number }[] = [
94	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
95	  { applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD, rate: -LOYALTY_DISCOUNT },
96	  { applies: (ctx) => ctx.quoteIndex > 0, rate: -FOLLOWUP_CONTRACT_DISCOUNT },
97	];
98	
99	const policyModifierRateFor = (ctx: PolicyContext): number =>
100	  POLICY_MODIFIER_RULES.reduce((rate, rule) => rate + (rule.applies(ctx) ? rule.rate : 0), 0);
101	
102	const computePremium = (items: Item[], ctx: PolicyContext): number => {
103	  const policyBase = sumBasePremiumsFor(items);
104	  const itemSurcharges = itemSurchargesFor(items);
105	  const policyModifiers = policyBase * policyModifierRateFor(ctx);
106	  return policyBase + itemSurcharges + policyModifiers + PROCESSING_FEE;
107	};
108	
109	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
110	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
111	const roundUpToGold = (amount: number): number =>
112	  Math.ceil(Math.round(amount * 1e6) / 1e6);
113	
114	type Policy = { items: Item[]; cap: number; remainingCap: number };
115	
116	const insuranceSumFor = (items: Item[]): number =>
117	  items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
118	
119	const roundDownToGold = (amount: number): number =>
120	  Math.floor(Math.round(amount * 1e6) / 1e6);
121	
122	const reimbursementRateFor = (item: Item): number =>
123	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
124	    ? HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT
125	    : 1;
126	
127	const payoutForDamage = (damage: Damage, item: Item): number =>
128	  Math.max(0, damage.amount * reimbursementRateFor(item) - DEDUCTIBLE_PER_DAMAGE);
129	
130	const grossPayoutFor = (incident: Incident, policy: Policy): number =>
131	  incident.damages.reduce((sum, d) => {
132	    const item = policy.items.find((i) => i.type === d.itemType)!;
133	    return sum + payoutForDamage(d, item);
134	  }, 0);
135	
136	type ScenarioState = { policies: Policy[]; results: StepResult[] };
137	
138	const applyQuote = (
139	  state: ScenarioState,
140	  step: QuoteStep,
141	  customer: Customer,
142	): ScenarioState => {
143	  const ctx: PolicyContext = { customer, quoteIndex: state.policies.length };
144	  const cap = insuranceSumFor(step.items) * CAP_MULTIPLIER;
145	  const policy: Policy = { items: step.items, cap, remainingCap: cap };
146	  const result: QuoteResult = { premium: roundUpToGold(computePremium(step.items, ctx)) };
147	  return {
148	    policies: [...state.policies, policy],
149	    results: [...state.results, result],
150	  };
151	};
152	
153	const applyClaim = (state: ScenarioState, step: ClaimStep): ScenarioState => {
154	  const policy = state.policies[step.policy];
155	  const payout = roundDownToGold(Math.min(grossPayoutFor(step.incident, policy), policy.remainingCap));
156	  const updatedPolicy: Policy = { ...policy, remainingCap: policy.remainingCap - payout };
157	  return {
158	    policies: state.policies.map((p, i) => (i === step.policy ? updatedPolicy : p)),
159	    results: [...state.results, { payout, remainingCap: updatedPolicy.remainingCap }],
160	  };
161	};
162	
163	const applyStep = (customer: Customer) => (state: ScenarioState, step: Step): ScenarioState =>
164	  step.op === "quote" ? applyQuote(state, step, customer) : applyClaim(state, step);
165	
166	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
167	  const initial: ScenarioState = { policies: [], results: [] };
168	  const { results } = scenario.steps.reduce(applyStep(scenario.customer), initial);
169	  return { results };
170	};
171

